import{c as e,Q as o,j as s,m as a}from"./chunks/framework.CKo_DbFQ.js";const u=JSON.parse('{"title":"What is K3d Bootstrap Cluster?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":1781113651000}'),r={name:"guide/index.md"};function n(d,t,l,i,c,p){return o(),s("div",null,[...t[0]||(t[0]=[a('<h1 id="what-is-k3d-bootstrap-cluster" tabindex="-1">What is K3d Bootstrap Cluster? <a class="header-anchor" href="#what-is-k3d-bootstrap-cluster" aria-label="Permalink to &quot;What is K3d Bootstrap Cluster?&quot;">​</a></h1><p>This project creates an k3d demo cluster. It comes with an interactive setup, which allows you to setup a Kubernetes cluster for demo and showcase purposes.</p><p><code>k3d-bootstrap-cluster</code> uses <a href="https://github.com/k3d-io/k3d" target="_blank" rel="noreferrer">k3d</a> as base.</p><h2 id="optional-components" tabindex="-1">Optional components <a class="header-anchor" href="#optional-components" aria-label="Permalink to &quot;Optional components&quot;">​</a></h2><p>Every cluster ships with <strong>Kong Gateway (Gateway API)</strong> as the sole ingress controller (Traefik is disabled; Flannel is replaced by Cilium by default, or by Calico when selected). Kong installs Gateway API CRDs v1.5.1, Kong Ingress Controller (v3.5.6), a <code>GatewayClass</code>, and a <code>Gateway</code>. httpbin is exposed via <code>HTTPRoute</code>.</p><p>If you want to experiment with classic Ingress alongside Kong, install the <a href="/k3d-bootstrap-cluster/pr-73/showcases/haproxy.html">HAProxy Ingress showcase</a> after the cluster is up.</p><p>During interactive setup (<code>bash create-sample.sh</code>) you can choose the following optional components:</p><table tabindex="0"><thead><tr><th>Component</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Cilium CNI</strong></td><td>Yes</td><td>Replaces Flannel. eBPF-based networking with Kubernetes NetworkPolicy support. Mutually exclusive with Calico.</td></tr><tr><td><strong>Calico CNI</strong></td><td>No</td><td>Replaces Flannel. Enables Kubernetes NetworkPolicy support (needed for the Calico NetworkPolicies showcase). Mutually exclusive with Cilium.</td></tr><tr><td><strong>Kubernetes Dashboard (Headlamp)</strong></td><td>No</td><td>Web UI for cluster inspection.</td></tr><tr><td><strong>httpbin sample</strong></td><td>Yes</td><td>Deploys the httpbin demo app from the local registry into the <code>demo</code> namespace.</td></tr><tr><td><strong>Cluster API (CAPI)</strong></td><td>No</td><td>Enables Docker socket mount needed for CAPD-based workload clusters.</td></tr></tbody></table>',8)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
